const shippedQtyForOrderItem = `-- name: ShippedQtyForOrderItem :one
SELECT COALESCE(SUM(quantity), 0)::numeric(15,4) AS shipped FROM shipment_items WHERE order_item_id = $1
`

// ShippedQtyForOrderItem returns the total already shipped for an order line,
// used to cap new shipment quantities (§7 AC).
func (q *Queries) ShippedQtyForOrderItem(ctx context.Context, orderItemID int64) (string, error) {
	row := q.db.QueryRow(ctx, shippedQtyForOrderItem, orderItemID)
	var shipped string
	err := row.Scan(&shipped)
	return shipped, err
}

const sumCapturedForInvoice = `-- name: SumCapturedForInvoice :one
SELECT COALESCE(SUM(amount), 0)::numeric(15,4) AS captured
FROM payments WHERE invoice_id = $1 AND status = 'captured'
`

// SumCapturedForInvoice totals captured payments against an invoice.
func (q *Queries) SumCapturedForInvoice(ctx context.Context, invoiceID *int64) (string, error) {
	row := q.db.QueryRow(ctx, sumCapturedForInvoice, invoiceID)
	var captured string
	err := row.Scan(&captured)
	return captured, err
}

const sumOpenInvoices = `-- name: SumOpenInvoices :one
SELECT COALESCE(SUM(grand_total), 0)::numeric(15,4) AS open_total
FROM invoices WHERE customer_id = $1 AND status IN ('issued','overdue')
`

// SumOpenInvoices totals a customer's unpaid (issued/overdue) invoices, used to
// enforce the credit limit when paying on terms.
func (q *Queries) SumOpenInvoices(ctx context.Context, customerID int64) (string, error) {
	row := q.db.QueryRow(ctx, sumOpenInvoices, customerID)
	var open_total string
	err := row.Scan(&open_total)
	return open_total, err
}

const upsertInvoiceDocument = `-- name: UpsertInvoiceDocument :exec
INSERT INTO invoice_documents (invoice_id, content_type, bytes)
VALUES ($1, $2, $3)
ON CONFLICT (invoice_id)
DO UPDATE SET content_type = EXCLUDED.content_type, bytes = EXCLUDED.bytes, generated_at = now()
`

type UpsertInvoiceDocumentParams struct {
	InvoiceID   int64  `json:"invoice_id"`
	ContentType string `json:"content_type"`
	Bytes       []byte `json:"bytes"`
}

// UpsertInvoiceDocument stores (or replaces, on regeneration) the rendered PDF.
func (q *Queries) UpsertInvoiceDocument(ctx context.Context, arg UpsertInvoiceDocumentParams) error {
	_, err := q.db.Exec(ctx, upsertInvoiceDocument, arg.InvoiceID, arg.ContentType, arg.Bytes)
	return err
}
